303	// ---------------------------------------------------------------------------
304	// DesignerTabBar
305	// ---------------------------------------------------------------------------
306	
307	export default function DesignerTabBar({
308	  tabs,
309	  activeTabId,
310	  onSwitchTab,
311	  onCloseTab,
312	  onCloseOthers,
313	  onCloseAll,
314	  onRenameTab,
315	}: DesignerTabBarProps) {
316	  const scrollRef = useRef<HTMLDivElement>(null);
317	  const [canScrollLeft, setCanScrollLeft] = useState(false);
318	  const [canScrollRight, setCanScrollRight] = useState(false);
319	
320	  // Check scroll position
321	  const checkScroll = useCallback(() => {
322	    const el = scrollRef.current;
323	    if (!el) return;
324	    setCanScrollLeft(el.scrollLeft > 0);
325	    setCanScrollRight(el.scrollLeft + el.clientWidth < el.scrollWidth - 1);
326	  }, []);
327	
328	  useEffect(() => {
329	    const el = scrollRef.current;
330	    if (!el) return;
331	    checkScroll();
332	    el.addEventListener("scroll", checkScroll, { passive: true });
333	    const ro = new ResizeObserver(checkScroll);
334	    ro.observe(el);
335	    return () => {
336	      el.removeEventListener("scroll", checkScroll);
337	      ro.disconnect();
338	    };
339	  }, [checkScroll]);
340	
341	  // Re-check when tabs change
342	  useEffect(() => {
343	    checkScroll();
344	  }, [tabs, checkScroll]);
345	
346	  // Scroll active tab into view when it changes
347	  useEffect(() => {
348	    if (!activeTabId || !scrollRef.current) return;
349	    const activeEl = scrollRef.current.querySelector(
350	      `[aria-selected="true"]`,
351	    ) as HTMLElement | null;
352	    if (activeEl) {
353	      activeEl.scrollIntoView({ inline: "nearest", block: "nearest" });
354	    }
355	  }, [activeTabId]);
356	
357	  const scrollBy = useCallback((delta: number) => {
358	    scrollRef.current?.scrollBy({ left: delta, behavior: "smooth" });
359	  }, []);
360	
361	  if (tabs.length === 0) return null;
362	
363	  return (
364	    <div
365	      role="tablist"
366	      aria-label="Open graphics"
367	      style={{
368	        display: "flex",
369	        alignItems: "stretch",
370	        height: 36,
371	        flexShrink: 0,
372	        background: "var(--io-surface)",
373	        borderBottom: "1px solid var(--io-border)",
374	        overflow: "hidden",
375	      }}
376	    >
377	      {/* Left scroll arrow */}
378	      <ScrollArrow
379	        direction="left"
380	        visible={canScrollLeft}
381	        onClick={() => scrollBy(-120)}
382	      />
383	
384	      {/* Scrollable tab strip */}
385	      <div
386	        ref={scrollRef}
387	        style={{
388	          display: "flex",
389	          alignItems: "stretch",
390	          flex: 1,
391	          overflowX: "auto",
392	          overflowY: "hidden",
393	          scrollbarWidth: "none",
394	          // Hide webkit scrollbar
395	        }}
396	      >
397	        <style>{`
398	          .designer-tab-scroll::-webkit-scrollbar { display: none; }
399	        `}</style>
400	        <div
401	          className="designer-tab-scroll"
402	          style={{ display: "flex", alignItems: "stretch", height: "100%" }}
403	        >
404	          {tabs.map((tab) => (
405	            <TabItem
406	              key={tab.id}
407	              tab={tab}
408	              active={tab.id === activeTabId}
409	              onSwitch={() => onSwitchTab(tab.id)}
410	              onClose={() => onCloseTab(tab.id)}
411	              onCloseOthers={() => onCloseOthers(tab.id)}
412	              onCloseAll={onCloseAll}
413	              onRename={() => onRenameTab(tab.id)}
414	            />
415	          ))}
416	        </div>
417	      </div>
418	
419	      {/* Right scroll arrow */}
420	      <ScrollArrow
421	        direction="right"
422	        visible={canScrollRight}
423	        onClick={() => scrollBy(120)}
424	      />
425	    </div>
426	  );
427	}
