  if (diffDay < 30) return `${diffDay} day${diffDay !== 1 ? "s" : ""} ago`;
  const diffMo = Math.floor(diffDay / 30);
  if (diffMo < 12) return `${diffMo} month${diffMo !== 1 ? "s" : ""} ago`;
  const diffYr = Math.floor(diffMo / 12);
  return `${diffYr} year${diffYr !== 1 ? "s" : ""} ago`;
}

