// Symbol Library page — Designer module
// Route: /designer/symbols (permission: designer:read)
// See design-docs/35_SHAPE_LIBRARY.md for long-term browser requirements.

import React, { useEffect, useRef, useState } from "react";
import { graphicsApi } from "../../api/graphics";

// ---------------------------------------------------------------------------
// Category data (Tier 1 DCS equipment shapes per doc 35)
// ---------------------------------------------------------------------------

interface SymbolCategory {
  id: string;
  label: string;
  description: string;
  count: number;
}

const SYMBOL_CATEGORIES: SymbolCategory[] = [
  {
    id: "vessels",
    label: "Vessels",
    description: "Tanks, drums, and storage vessels",
    count: 6,
  },
  {
    id: "pumps",
    label: "Pumps",
    description: "Centrifugal, positive-displacement, and specialty pumps",
    count: 5,
  },
  {
    id: "valves",
    label: "Valves",
    description: "Gate, globe, ball, butterfly, and control valves",
    count: 8,
  },
  {
    id: "heat-exchangers",
    label: "Heat Exchangers",
    description: "Shell-and-tube, plate, and air coolers",
    count: 4,
  },
  {
    id: "columns",
    label: "Columns",
    description: "Distillation and absorption columns",
    count: 2,
  },
  {
    id: "compressors",
    label: "Compressors",
    description: "Centrifugal and reciprocating compressors",
    count: 4,
  },
  {
    id: "instruments",
    label: "Instruments",
    description: "Transmitters, indicators, and controllers",
    count: 12,
  },
  {
    id: "piping",
    label: "Piping",
    description: "Pipes, fittings, and flow direction indicators",
    count: 8,
  },
];

// ---------------------------------------------------------------------------
// SymbolCategory card
// ---------------------------------------------------------------------------

function CategoryCard({ category }: { category: SymbolCategory }) {
  return (
    <div
      style={{
        background: "var(--io-surface-elevated)",
        border: "1px solid var(--io-border)",
        borderRadius: "var(--io-radius)",
        padding: "16px",
        display: "flex",
        flexDirection: "column",
        gap: "8px",
        minWidth: 0,
        cursor: "default",
      }}
    >
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
        }}
      >
        <span
          style={{
            fontSize: "14px",
            fontWeight: 600,
            color: "var(--io-text-primary)",
          }}
        >
          {category.label}
        </span>
        <span
          style={{
            fontSize: "11px",
            fontWeight: 600,
            color: "var(--io-accent)",
            background: "color-mix(in srgb, var(--io-accent) 12%, transparent)",
            borderRadius: "4px",
            padding: "2px 7px",
          }}
        >
          {category.count}
        </span>
      </div>
      <div
        style={{
          fontSize: "12px",
          color: "var(--io-text-secondary)",
          lineHeight: 1.4,
        }}
      >
        {category.description}
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// Custom shape row
// ---------------------------------------------------------------------------

interface CustomShapeItem {
  id: string;
  shape_id: string;
  name: string;
  category: string;
  source: "user";
  created_at: string | null;
}

function CustomShapeRow({
  shape,
  onDelete,
}: {
  shape: CustomShapeItem;
  onDelete: (id: string) => void;
}) {
  const [deleting, setDeleting] = useState(false);

  async function handleDelete() {
    if (!confirm(`Delete custom shape "${shape.name}"? This cannot be undone.`))
      return;
    setDeleting(true);
    try {
      await graphicsApi.deleteUserShape(shape.id);
      onDelete(shape.id);
    } catch {
      alert("Failed to delete shape. Please try again.");
      setDeleting(false);
    }
  }

  return (
    <div
      style={{
        display: "flex",
        alignItems: "center",
        gap: "12px",
        padding: "10px 12px",
        background: "var(--io-surface-elevated)",
        border: "1px solid var(--io-border)",
        borderRadius: "var(--io-radius)",
      }}
    >
      {/* Shape icon placeholder */}
      <div
        style={{
          width: 36,
          height: 36,
          background: "var(--io-surface)",
          border: "1px solid var(--io-border)",
          borderRadius: 4,
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          flexShrink: 0,
        }}
      >
        <svg width="18" height="18" viewBox="0 0 18 18" fill="none">
          <rect
            x="2"
            y="4"
            width="14"
            height="10"
            rx="1"
            stroke="currentColor"
            strokeWidth="1.2"

