// ---------------------------------------------------------------------------
// Custom Shapes section
// ---------------------------------------------------------------------------

function CustomShapesSection() {
  const [shapes, setShapes] = useState<CustomShapeItem[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [uploading, setUploading] = useState(false);
  const [uploadError, setUploadError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  useEffect(() => {
    loadShapes();
  }, []);

  async function loadShapes() {
    setLoading(true);
    setError(null);
    try {
      const resp = await graphicsApi.listUserShapes();
      if (resp.success) {
        setShapes(resp.data.data ?? []);
      } else {
        setError(resp.error.message ?? "Failed to load custom shapes");
      }
    } catch (err) {
      setError(
        err instanceof Error ? err.message : "Failed to load custom shapes",
      );
    } finally {
      setLoading(false);
    }
  }

  async function handleUpload(e: React.ChangeEvent<HTMLInputElement>) {
    const file = e.target.files?.[0];
    if (!file) return;
    // Reset input so the same file can be re-uploaded after a failed attempt
    e.target.value = "";

    setUploading(true);
    setUploadError(null);
    try {
      const result = await graphicsApi.uploadUserShape(file);
      setShapes((prev) => [...prev, { ...result, created_at: null }]);
    } catch (err) {
      setUploadError(err instanceof Error ? err.message : "Upload failed");
    } finally {
      setUploading(false);
    }
  }

  function handleDelete(id: string) {
    setShapes((prev) => prev.filter((s) => s.id !== id));
  }

  return (
    <div>
      {/* Section header */}
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          marginBottom: "16px",
          gap: 12,
        }}
      >
        <div>
          <h2
            style={{
              margin: 0,
              fontSize: "16px",
              fontWeight: 700,
              color: "var(--io-text-primary)",
            }}
          >
            Custom Shapes
          </h2>
          <p
            style={{
              margin: "2px 0 0",
              fontSize: "12px",
              color: "var(--io-text-secondary)",
            }}
          >
            Your uploaded SVG shapes, available in the Designer canvas palette.
          </p>
        </div>

        <button
          onClick={() => fileInputRef.current?.click()}
          disabled={uploading}
          style={{
            display: "flex",
            alignItems: "center",
            gap: 6,
            padding: "7px 14px",
            background: "var(--io-accent)",
            border: "none",
            borderRadius: "var(--io-radius)",
            color: "#09090b",
            fontSize: 12,
            fontWeight: 600,
            cursor: uploading ? "wait" : "pointer",
            whiteSpace: "nowrap",
            flexShrink: 0,
          }}
        >
          {uploading ? "Uploading…" : "Upload SVG"}
        </button>

        <input
          ref={fileInputRef}
          type="file"
          accept=".svg,image/svg+xml"
          onChange={handleUpload}
          style={{ display: "none" }}
        />
      </div>

      {/* Upload error */}
      {uploadError && (
        <div
          style={{
            padding: "10px 12px",
            background: "color-mix(in srgb, #ef4444 10%, transparent)",
