// ---------------------------------------------------------------------------
// DeleteDialog
// ---------------------------------------------------------------------------

interface DeleteDialogProps {
  graphicName: string;
  onConfirm: () => void;
  onCancel: () => void;
  isPending: boolean;
}

function DeleteDialog({
  graphicName,
  onConfirm,
  onCancel,
  isPending,
}: DeleteDialogProps) {
  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        background: "rgba(0,0,0,0.6)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        zIndex: 1000,
      }}
      onClick={onCancel}
    >
      <div
        style={{
          background: "var(--io-surface)",
          border: "1px solid var(--io-border)",
          borderRadius: "var(--io-radius)",
          padding: "24px 28px",
          maxWidth: 420,
          width: "90%",
          boxShadow: "0 16px 48px rgba(0,0,0,0.5)",
        }}
        onClick={(e) => e.stopPropagation()}
      >
        <h3
          style={{
            margin: "0 0 8px",
            fontSize: 16,
            fontWeight: 600,
            color: "var(--io-text-primary)",
          }}
        >
          Delete Graphic
        </h3>
        <p
          style={{
            margin: "0 0 20px",
            fontSize: 13,
            color: "var(--io-text-secondary)",
            lineHeight: 1.5,
          }}
        >
          Delete{" "}
          <strong style={{ color: "var(--io-text-primary)" }}>
            "{graphicName}"
          </strong>
          ? This action cannot be undone.
        </p>
        <div style={{ display: "flex", gap: 10, justifyContent: "flex-end" }}>
          <button
            onClick={onCancel}
            disabled={isPending}
            style={{
              padding: "8px 18px",
              background: "var(--io-surface-elevated)",
              border: "1px solid var(--io-border)",
              borderRadius: "var(--io-radius)",
              color: "var(--io-text-primary)",
              fontSize: 13,
              fontWeight: 500,
              cursor: isPending ? "not-allowed" : "pointer",
              opacity: isPending ? 0.6 : 1,
            }}
          >
            Cancel
          </button>
          <button
            onClick={onConfirm}
            disabled={isPending}
            style={{
              padding: "8px 18px",
              background: isPending ? "rgba(239,68,68,0.4)" : "#ef4444",
              border: "none",
              borderRadius: "var(--io-radius)",
              color: "#fff",
              fontSize: 13,
              fontWeight: 600,
              cursor: isPending ? "not-allowed" : "pointer",
            }}
          >
            {isPending ? "Deleting…" : "Delete"}
          </button>
        </div>
      </div>
    </div>
  );
}

// ---------------------------------------------------------------------------
// EmptyState
// ---------------------------------------------------------------------------

function EmptyState({
  onCreate,
  canCreate,
  hasFilters,
}: {
  onCreate: () => void;
  canCreate: boolean;
  hasFilters: boolean;
}) {
  return (
    <div
      style={{
        flex: 1,
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: "center",
        gap: 16,
        padding: 40,
        color: "var(--io-text-muted)",
      }}
    >
      <svg
        width="56"
        height="56"
        viewBox="0 0 24 24"
        fill="none"
        stroke="currentColor"
        strokeWidth="1"
        opacity={0.35}
      >
        <rect x="3" y="3" width="18" height="18" rx="2" />
        <path d="M3 9h18M9 21V9" />
        <line x1="12" y1="5" x2="12" y2="7" strokeWidth="1.5" />
        <line x1="12" y1="12" x2="12" y2="18" strokeWidth="1.5" />
        <line x1="9" y1="15" x2="15" y2="15" strokeWidth="1.5" />
      </svg>
      <div style={{ textAlign: "center" }}>
        <p
          style={{
            margin: "0 0 6px",
            fontSize: 15,
            fontWeight: 600,
            color: "var(--io-text-primary)",
          }}
        >
          {hasFilters
            ? "No graphics match your filters"
            : "No process graphics yet"}
        </p>
        <p
          style={{
            margin: 0,
            fontSize: 13,
            color: "var(--io-text-muted)",
            maxWidth: 320,
          }}
        >
          {hasFilters
            ? "Try adjusting your search or filter criteria."
            : "Create your first graphic to get started."}
        </p>
      </div>
      {canCreate && !hasFilters && (
        <button
          onClick={onCreate}
          style={{
            marginTop: 4,
            padding: "9px 20px",
            background: "var(--io-accent)",
            border: "none",
            borderRadius: "var(--io-radius)",
            color: "#fff",
            fontSize: 13,
            fontWeight: 600,
            cursor: "pointer",
          }}
        >
          Create Graphic
        </button>
      )}
    </div>
  );
}

