// ---------------------------------------------------------------------------

export default function DesignerGraphicsList() {
  const navigate = useNavigate();
  const queryClient = useQueryClient();
  const { user } = useAuthStore();

  const canWrite = user?.permissions.includes("designer:write") ?? false;
  const canDelete = user?.permissions.includes("designer:delete") ?? false;

  // Filter state
  const [search, setSearch] = useState("");
  const [scopeFilter, setScopeFilter] = useState<"all" | "console" | "process">(
    "all",
  );
  const [modeFilter, setModeFilter] = useState<
    "all" | "graphic" | "dashboard" | "report"
  >("all");
  const [page, setPage] = useState(1);

  // Delete confirmation state
  const [deleteTarget, setDeleteTarget] = useState<{
    id: string;
    name: string;
  } | null>(null);

  // --------------------------------------------------------------------------
  // Data
  // --------------------------------------------------------------------------

  const showAllUsers = useAdminToggleStore((s) => s.showAllUsersObjects);
  const setShowAllUsers = useAdminToggleStore((s) => s.setShowAllUsersObjects);

  const { data, isLoading, isError } = useQuery({
    queryKey: [
      "design-objects",
      { scope: scopeFilter, mode: modeFilter, search, showAllUsers },
    ],
    queryFn: () => graphicsApi.list({ includeAllUsers: showAllUsers }),
    staleTime: 30_000,
  });

  // Guard against both paginated ({ data: [...] }) and flat (array) API shapes.
  // The client unwraps the envelope differently depending on whether the server
  // includes a `pagination` key, so data.data may be the array itself or an
  // object with a nested `data` property.
  const allGraphics: GraphicSummary[] = (
    data?.success === true
      ? Array.isArray(data.data)
        ? data.data
        : ((data.data as { data?: GraphicSummary[] })?.data ?? [])
      : []
  )
    // Auto-save entries are stored as hidden graphics with a reserved name prefix.
    // They are never surfaced in the list — they exist only for crash recovery.
    .filter((g) => !g.name.startsWith("__autosave_"));

  // Client-side filtering
  const filtered = useMemo(() => {
    let list = allGraphics;
    if (search.trim()) {
      const q = search.trim().toLowerCase();
      list = list.filter(
        (g) =>
          g.name.toLowerCase().includes(q) ||
          (g.description ?? "").toLowerCase().includes(q),
      );
    }
    if (scopeFilter !== "all") {
      list = list.filter((g) => g.graphicScope === scopeFilter);
    }
    if (modeFilter !== "all") {
      list = list.filter((g) => g.designMode === modeFilter);
    }
    return list;
  }, [allGraphics, search, scopeFilter, modeFilter]);

  const paginated = filtered.slice(0, page * PAGE_SIZE);
  const hasMore = page * PAGE_SIZE < filtered.length;

  // Reset page when filters change
  const handleSearch = (v: string) => {
    setSearch(v);
    setPage(1);
  };
  const handleScope = (v: string) => {
    setScopeFilter(v as typeof scopeFilter);
    setPage(1);
  };
  const handleMode = (v: string) => {
    setModeFilter(v as typeof modeFilter);
    setPage(1);
  };

  // --------------------------------------------------------------------------
  // Delete mutation
  // --------------------------------------------------------------------------

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      const result = await graphicsApi.remove(id);
      if (!result.success) throw new Error(result.error.message);
    },
    onSuccess: () => {
      queryClient.invalidateQueries({
        queryKey: ["design-objects"],
        exact: false,
      });
      setDeleteTarget(null);
      showToast({ title: "Graphic deleted", variant: "success" });
    },
    onError: () => {
      showToast({
        title: "Delete failed",
        description: "Could not delete the graphic. Please try again.",
        variant: "error",
      });
    },
  });

  const handleDeleteRequest = (id: string, name: string) => {
    if (!canDelete) return;
    setDeleteTarget({ id, name });
  };
  const handleDeleteConfirm = () => {
    if (deleteTarget) deleteMutation.mutate(deleteTarget.id);
  };
  const handleDeleteCancel = () => setDeleteTarget(null);

  // --------------------------------------------------------------------------
  // Render
  // --------------------------------------------------------------------------

  return (
    <>
      <div
        style={{
          display: "flex",
          flexDirection: "column",
          height: "100%",
          background: "var(--io-surface-primary)",
          overflow: "hidden",
        }}
      >
        {/* ------------------------------------------------------------------ */}
        {/* Header bar                                                          */}
        {/* ------------------------------------------------------------------ */}
        <div
          style={{
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between",
            padding: "0 20px",
            height: 48,
            flexShrink: 0,
            background: "var(--io-surface)",
            borderBottom: "1px solid var(--io-border)",
          }}
        >
          {/* Breadcrumb */}
          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <button
              onClick={() => navigate("/designer")}
              style={{
                background: "none",
                border: "none",
                color: "var(--io-text-muted)",
                cursor: "pointer",
                fontSize: 13,
                padding: "4px 0",
                lineHeight: 1,
              }}
            >
              Designer
            </button>
            <span style={{ color: "var(--io-border)", fontSize: 13 }}>/</span>
            <span
              style={{
                fontSize: 14,
                fontWeight: 600,
                color: "var(--io-text-primary)",
              }}
            >
              Process Graphics
            </span>
          </div>

          {/* New Graphic button */}
          {canWrite && (
            <button
              onClick={() => navigate("/designer/graphics/new")}
              style={{
                display: "flex",
                alignItems: "center",
                gap: 6,
                padding: "7px 16px",
                background: "var(--io-accent)",
                border: "none",
                borderRadius: "var(--io-radius)",
                color: "#fff",

            }}
          >
            Upload an SVG file to add it to your custom shape library. Custom
            shapes appear in the Designer canvas palette alongside built-in
            ISA-101 shapes.
          </div>
        </div>
      )}

      {/* Shape list */}
      {!loading && !error && shapes.length > 0 && (
        <div style={{ display: "flex", flexDirection: "column", gap: "8px" }}>
          {shapes.map((shape) => (
            <CustomShapeRow
              key={shape.id}
              shape={shape}
              onDelete={handleDelete}
            />
          ))}
        </div>
      )}
    </div>
  );
}

// ---------------------------------------------------------------------------
// SymbolLibrary page
// ---------------------------------------------------------------------------

export default function SymbolLibrary() {
  return (
    <div
      style={{
        height: "100%",
        overflowY: "auto",
        background: "var(--io-surface-primary)",
        padding: "24px",
      }}
    >
      <div style={{ maxWidth: "900px", margin: "0 auto" }}>
        {/* Page header */}
        <div style={{ marginBottom: "24px" }}>
          <h1
            style={{
              margin: 0,
              fontSize: "20px",
              fontWeight: 700,
              color: "var(--io-text-primary)",
            }}
          >
            Symbol Library
          </h1>
          <p
            style={{
              margin: "4px 0 0",
              fontSize: "13px",
              color: "var(--io-text-secondary)",
            }}
          >
            Browse ISA-101 compliant DCS equipment shapes and manage your custom
            shapes.
          </p>
        </div>

        {/* Built-in ISA-101 categories */}
        <div style={{ marginBottom: "32px" }}>
          <h2
            style={{
              margin: "0 0 12px",
              fontSize: "15px",
              fontWeight: 600,
              color: "var(--io-text-primary)",
            }}
          >
            ISA-101 Equipment Shapes
          </h2>
          <div
            style={{
              display: "grid",
              gridTemplateColumns: "repeat(auto-fill, minmax(240px, 1fr))",
              gap: "12px",
            }}
          >
            {SYMBOL_CATEGORIES.map((cat) => (
              <CategoryCard key={cat.id} category={cat} />
            ))}
          </div>
        </div>

        {/* Divider */}
        <div
          style={{
            height: 1,
            background: "var(--io-border)",
            marginBottom: "32px",
          }}
        />

        {/* Custom shapes section */}
        <CustomShapesSection />
      </div>
    </div>
  );
}

    clampWidth(width),
    clampHeight(height),
    autoHeight,
    mode === "graphic" ? scope : null,
  );
}

const visiblePresets = ASPECT_PRESETS.filter(
  (p) => !p.reportOnly || mode === "report",
);

const inputStyle: React.CSSProperties = {
  width: "100%",
  padding: "6px 8px",
  background: "var(--io-surface)",
  border: "1px solid var(--io-border)",
  borderRadius: "var(--io-radius)",
  color: "var(--io-text-primary)",
  fontSize: 13,
  outline: "none",
  boxSizing: "border-box",
};

const labelStyle: React.CSSProperties = {
  display: "block",
  fontSize: 11,
  fontWeight: 600,
  color: "var(--io-text-muted)",
  textTransform: "uppercase",
  letterSpacing: "0.05em",
  marginBottom: 4,
};

return (
  <div
    style={{
      position: "fixed",
      inset: 0,
      zIndex: 1000,
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      background: "rgba(0,0,0,0.6)",
    }}
  >
    <form
      onSubmit={handleSubmit}
      style={{
        background: "var(--io-surface-elevated)",
        border: "1px solid var(--io-border)",
        borderRadius: "var(--io-radius)",
        padding: 24,
        width: 440,
        maxWidth: "92%",
        display: "flex",
        flexDirection: "column",
        gap: 16,
      }}
    >
      <div
        style={{
          fontSize: 15,
          fontWeight: 600,
          color: "var(--io-text-primary)",
        }}
      >
        {mode === "dashboard"
          ? "New Dashboard"
          : mode === "report"
            ? "New Report"
            : "New Graphic"}
      </div>

      {/* Name */}
      <div>
        <label style={labelStyle}>Name</label>
        <input
          type="text"
          value={name}
          onChange={(e) => setName(e.target.value)}
          autoFocus
          style={inputStyle}
        />
      </div>

      {/* Type / Mode */}
      <div>
        <label style={labelStyle}>Type</label>
        <div style={{ display: "flex", gap: 8 }}>
          {(["graphic", "dashboard", "report"] as const).map((m) => (
            <button
              key={m}
              type="button"
              onClick={() => handleModeChange(m)}
              style={{
                flex: 1,
