function handleZoomIn() {
  zoomTo(viewport.zoom * 1.25);
}

function handleZoomOut() {
  zoomTo(viewport.zoom / 1.25);
}

return (
  <div
    style={{
      height: 44,
      flexShrink: 0,
      display: "flex",
      alignItems: "center",
      gap: 2,
      padding: "0 8px",
      background: "var(--io-surface)",
      borderBottom: "1px solid var(--io-border)",
      overflow: "hidden",
    }}
  >
    {/* Undo / Redo */}
    <IconBtn
      onClick={undo}
      disabled={!canUndo}
      title={
        canUndo && undoDescription
          ? `Undo: ${undoDescription}`
          : "Undo (Ctrl+Z)"
      }
    >
      <IconUndo />
    </IconBtn>
    <IconBtn
      onClick={redo}
      disabled={!canRedo}
      title={
        canRedo && redoDescription
          ? `Redo: ${redoDescription}`
          : "Redo (Ctrl+Y)"
      }
    >
      <IconRedo />
    </IconBtn>

    <Sep />

    {/* Selector button */}
    <IconBtn
      onClick={() => setTool("select")}
      active={activeTool === "select"}
      title="Select (V)"
    >
      <IconSelect />
    </IconBtn>

    {/* Group button — enabled when ≥2 non-pipe nodes selected */}
    <IconBtn
      onClick={() => {
        if (canGroup)
          document.dispatchEvent(new CustomEvent("io:toolbar-group"));
      }}
      disabled={!canGroup || readOnly}
      title="Group Selection (Ctrl+G)"
    >
      <IconGroup />
    </IconBtn>

    {/* Ungroup button — enabled when exactly 1 group node selected */}
    <IconBtn
      onClick={() => {
        if (canUngroup)
          document.dispatchEvent(new CustomEvent("io:toolbar-ungroup"));
      }}
      disabled={!canUngroup || readOnly}
      title="Ungroup (Ctrl+Shift+G)"
    >
      <IconUngroup />
    </IconBtn>

    <Sep />

    {/* Draw tools — hidden in read-only mode */}
    {visibleDrawTools.map((tool) => (
      <IconBtn
        key={tool.id}
        onClick={() => !readOnly && setTool(tool.id)}
        active={activeTool === tool.id}
        disabled={readOnly && tool.id !== "pan"}
        title={
          readOnly && tool.id !== "pan"
            ? "Read-only — designer:write required"
            : `${tool.label} (${tool.shortcut})`
        }
      >
        {tool.icon}
      </IconBtn>
    ))}

